using System;
using Vec3 = System.Numerics.Vector3;
using ProgressiveNormals;

public static class NormalTableData
{
    static public Vec3 GetNormalByIndex(int index)
    {
        return new Vec3(_normalTable[index * 3], _normalTable[index * 3 + 1], _normalTable[index * 3 + 2]);
    }

    // Reconstructs the two SpatialLookup trees directly from baked data — no tree building at startup.
    public static SpatialLookup BuildTree128()
        => SpatialLookup.FromBakedData(_centroids128, _radii128, _ranges128, _indices128, GetNormalByIndex);
    public static SpatialLookup BuildTree32768()
        => SpatialLookup.FromBakedData(_centroids32768, _radii32768, _ranges32768, _indices32768, GetNormalByIndex);

